var e=[{id:`L4_1`,type:`dialog`,speaker:`JOOSHIYOON_DELTA_NULL_NULL`,text:{KOREA:`와아, 압축된 공간을 가르면서 단숨에 날아가는 이 기분!`,JPN:`わあ……圧縮された空間を分けて、一気に飛んでいく気分って爽快！`,ENG:`Whoaa! I feel like I'm flying, cutting through compressed space!`,TWN:`哇，這種破開壓縮空間，一口氣飛上天的感覺！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`JOOSHIYOON_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`JOOSHIYOON_DELTA_NULL_NULL`,text:{KOREA:`한 번 뛸 때마다 CRF를 왕창 잡아먹는 것 빼곤 꽤 나쁘지 않은데요, 이 슈트?`,JPN:`一度ジャンプするごとに、私のCRFがわんさか削られる以外は悪くありませんね、このスーツ！`,ENG:`Although it eats up a lot of my CRF every time I jump, this suit isn't too bad!`,TWN:`除了每跳躍一次，我的CRF就狠狠減少以外，這件戰鬥裝備還不賴嘛？`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`JOOSHIYOON_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`JOOSHIYOON_DELTA_NULL_NULL`,text:{KOREA:`카린 양은 어때요?`,JPN:`カリンさんはどうですか？`,ENG:`How are you doing, Karin?`,TWN:`卡琳你怎麼樣？`},stage:{bg:`COUNTERSIDE_ANCIENT`,slots:{L:{char_id:`JOOSHIYOON_DELTA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`KARIN_DELTA_NEXT_NULL`,text:{KOREA:`머, 멀미가! 다이브 멀미도 안 하는 체질인데!`,JPN:`よ、酔います！　ダイブでも酔わない体質なのに！`,ENG:`I-I feel like I'm gonna be sick! But I don't even get motion sickness when I dive!`,TWN:`我，我……我頭好暈！我的體質明明躍入時是不會暈的！`},stage:{bg:`COUNTERSIDE_ANCIENT`,slots:{L:{char_id:`JOOSHIYOON_DELTA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`KARIN_DELTA_NEXT_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`JOOSHIYOON_DELTA_NULL_NULL`,text:{KOREA:`하하, 그런데 어쩌나 여기서 속도 줄이면 늦을지도 모른다고요?`,JPN:`ハハ、でもどうしましょう、ここでスピードを落としたら間に合わないかもしれませんよ？`,ENG:`Hah hah, I could slow down, but then, we might arrive late!`,TWN:`哈哈，但如果我們在這裡減速可能會來不及喔?`},stage:{bg:`COUNTERSIDE_ANCIENT`,slots:{L:{char_id:`JOOSHIYOON_DELTA_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`KARIN_DELTA_NEXT_NULL`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`KARIN_DELTA_NEXT_NULL`,text:{KOREA:`그, 그럼 말 시키지 말고 계속 뛰기나 해요!`,JPN:`じゃ、じゃあ話かけないで走ることに集中してください！`,ENG:`Th-then stop talking to me and jump!`,TWN:`那，那就別廢話，繼續跳！`},stage:{bg:`COUNTERSIDE_ANCIENT`,slots:{L:{char_id:`JOOSHIYOON_DELTA_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`KARIN_DELTA_NEXT_NULL`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`JOOSHIYOON_DELTA_NULL_NULL`,text:{KOREA:`엇차!? 잘 못 뛰었다!!`,JPN:`おっと！　ジャンプを間違えた！！`,ENG:`Whoops?! I jumped wrong!!`,TWN:`哎呀！？跳錯啦！！`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`JOOSHIYOON_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`JOOSHIYOON_DELTA_NULL_NULL`,text:{KOREA:`하, 하하. 이거 어쩌죠, 카린 양?`,JPN:`ハ、ハハ。どうしましょう、カリンさん？`,ENG:`Hah, hah hah. What do we do now, Karin?`,TWN:`哈，哈哈。怎麼辦，卡琳？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`JOOSHIYOON_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`JOOSHIYOON_DELTA_NULL_NULL`,text:{KOREA:`실수로 침식체 무리 한 가운데로 뛰어 버렸는데?`,JPN:`間違えて侵食体の群れのど真ん中に飛んでしまいましたが？`,ENG:`I accidentally jumped into the middle of a horde of C.O.s.`,TWN:`我不小心跳進侵蝕體群中間了？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`JOOSHIYOON_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`KARIN_DELTA_NEXT_NULL`,text:{KOREA:`하아, 중요한 작전이니까 이번에는 진지하게 임해달라고 부탁했잖아요.`,JPN:`はぁ、これは大事な作戦だから、今回だけは真剣に臨んでほしいと言ったじゃないですか。`,ENG:`*Sigh* I told you to please take this operation seriously.`,TWN:`哀……這次的作戰很重要，我已經拜託你認真一點。`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`KARIN_DELTA_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`KARIN_DELTA_NEXT_NULL`,text:{KOREA:`어쩔 수 없죠. 그대로 길을 열 테니까, 멈추지 말고 뛰어요. 시영 씨.`,JPN:`仕方ないですね。道を開きますから、このまま止まらずに走ってください、シノンさん。`,ENG:`Well, all right. I'll make way, so just keep jumping, Shiyoung.`,TWN:`沒辦法，我來開路吧，別停，繼續跳，時雨。`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`KARIN_DELTA_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`KARIN_DELTA_NEXT_NULL`,text:{KOREA:`디바이스 세트 온.`,JPN:`デバイスセットON。`,ENG:`Device set on.`,TWN:`設備開啟。`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`KARIN_DELTA_NEXT_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`KARIN_DELTA_NEXT_NULL`,text:{KOREA:`파츠 교체, 전술 무장 3번, <color=#ffd34c>로드 메이커</color>.`,JPN:`パーツ交換、戦術武装3番、<color=#ffd34c>ロードメーカー</color>。`,ENG:`Exchanging parts, Tactical Gear No. 3, <color=#ffd34c>Road Maker</color>.`,TWN:`更換零件，3號戰術裝備<color=#ffd34c>開路者</color>。`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`KARIN_DELTA_NEXT_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`JOOSHIYOON_DELTA_NULL_NULL`,text:{KOREA:`치, 침식체 뿐만 아니라 주변 지형까지 날려버렸어.`,JPN:`し、侵食体だけじゃなくて、周辺の地形まで吹っ飛ばした。`,ENG:`Y-you didn't just get rid of the C.O.s; you cleared out the surrounding landscape.`,TWN:`不僅是侵蝕體，連周圍的也都一塊清掉了？`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`JOOSHIYOON_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};